mapper.select:
SELECT a.*, t.type_name, u.admin_name FROM ACTIVITY a
LEFT JOIN ACTIVITYTYPE t ON a.act_type_id = t.type_id
LEFT JOIN AUSER u ON a.admin_id = u.admin_id WHERE a.act_id = #{actId}

SELECT a.*, t.type_name FROM ACTIVITY a
LEFT JOIN ACTIVITYTYPE t ON a.act_type_id = t.type_id
WHERE a.act_status IN (1, 2) ORDER BY a.act_start_time ASC LIMIT #{limit}
